// A Major is three Swiss stages followed by single-elimination playoffs.
// `opp` is the base opponent strength for matches in that round (it rises round
// to round, so the run gets harder). Per-match variance is added in the engine.
//
// Swiss stage: play until 3 wins (advance, 3-x) or 3 losses (eliminated, x-3).
// A loss does NOT end your run in the Swiss — only 3 losses do.
const SWISS_STAGES = [
  { ph: 'SWISS STAGE 1', opp: 4.4 },
  { ph: 'SWISS STAGE 2', opp: 5.1 },
  { ph: 'SWISS STAGE 3', opp: 5.8 },
];

// Playoffs: best-of-three, single elimination. Lose once and you're out.
const PLAYOFFS = [
  { ph: 'QUARTERFINAL', opp: 6.2 },
  { ph: 'SEMIFINAL', opp: 6.4 },
  { ph: 'GRAND FINAL', opp: 6.6 },
];
